var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"크아아악!!","JPN":"くうっ！！","ENG":"Aaah!","TWN":"唔啊啊啊！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"너, 넌 대체 뭐냐?! 어째서 클리포트 인자를 사용할 수 있는 거지?!","JPN":"な、何者だ！？\\nなぜクリフォト・ファクターを使えている！？","ENG":"W-what are you? How come you're using the Qliphoth Factors?","TWN":"妳、妳到底是什麼？！為什麼妳有辦法使用逆卡巴拉因子？！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_TRANS_HURT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"아, 아니 그보다 클리포트 레플리카 인자는 이론상 원본과 동일한 출력일 텐데......?","JPN":"いや、それよりもレプリカ・クリフォト・ファクターは\\n理論上、オリジナルと同じ出力のはずだが……？","ENG":"A-and Qliphoth Replica Factors should have the exact same energy output as the original ones!","TWN":"不、不對，逆卡巴拉複製因子理論上和本體的功率是一樣的啊……？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_TRANS_HURT","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"어떻게 이런 차이가?!","JPN":"なぜこれほどの違いが！？","ENG":"How can there be so big of a difference?","TWN":"差距怎麼會這麼大？！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_TRANS_HURT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"동일하다고? 그건 네 생각이겠지.","JPN":"同じだと？　それはお前の思い込みだろ。","ENG":"Same energy output? You're living in a daydream.","TWN":"妳說一樣？那是妳自己的想法吧。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"네놈이 찍어내고 있는 그건 결국 연마되지 못한 불순물 덩어리에 불과해.","JPN":"お前がコピーしているのは、結局研磨されていない不純物の塊に過ぎない。","ENG":"What you're producing in your factories are nothing but chunks of impurities.","TWN":"你們造的那些東西，不過是些沒有研磨過的雜質堆而已。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"성능은 저질인 주제에 재활용도 힘든 조잡한 싸구려 잡철이나 마찬가지지.","JPN":"性能も悪いくせに、リサイクルすらままならない鉄くず同然だ。","ENG":"They're like cheap scrap metals. They lack in quality and are hard to use.","TWN":"就跟性能低下，難以回收再利用的粗劣廉價原料一樣。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그러니 <color=#ffd34c>진짜 강철</color>과 부딪치면 그대로 깨져나갈 수밖에.","JPN":"だから<color=#ffd34c>本物の鋼鉄</color>とぶつかれば、壊れて当然だ。","ENG":"They're bound to shatter to pieces when swung against <color=#ffd34c>real steel</color>!","TWN":"所以和<color=#ffd34c>真正的鋼鐵</color>一撞，只有粉碎的份。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"허튼 소리!","JPN":"冗談じゃない！","ENG":"That's nonsense!","TWN":"胡說八道！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_TRANS_HURT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"이 클리포트 레플리카 인자는 수많은 희생을 통해 만들어 낸 테라사이드 시스템의 정수다!","JPN":"このレプリカ・クリフォト・ファクターは、数多くの犠牲をもとに誕生した、テラサイドシステムの真髄だ！","ENG":"Qliphoth Replica Factors are the pinnacle of technology made whole by System Terraside! They were built upon countless sacrifices!","TWN":"逆卡巴拉複製因子是用成千上萬的犧牲者造就的特拉賽德系統精髓。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_TRANS_HURT","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"이것이야말로 다가올 종말로부터 인류를 구원할 유일한 희망이란 말이다!","JPN":"これこそが、迫り来る終末から人類を救う唯一の希望なのだ！","ENG":"This is the one and only hope we have against the doom reserved for humanity!","TWN":"這才是能在即將到來的末日中，拯救人類的唯一希望！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_TRANS_HURT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"그런 것을 감히 불순물이나 찌꺼기 따위로 칭하는 건 용서 못할......","JPN":"そんなものを不純物や鉄くずなどと称するのは、許せん……","ENG":"You'll be damned for calling them impurities—","TWN":"而妳竟敢把它叫作雜質、殘渣，不可原諒……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_TRANS_HURT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"QUEEN_REPLACER_TRANS_HURT","text":{"KOREA":"크아악!!","JPN":"ぐああ！！","ENG":"Aaaargh!","TWN":"唔啊啊！！"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"개소리를 길게도 하는군.","JPN":"バカなことを言うな。","ENG":"Please, keep your jokes to yourself.","TWN":"廢話真多呢。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"나유빈이 그렇게 말하던가? 클리포트 인자로 인류를 구할 수 있다고?","JPN":"イチノセがそう言ったのか？　クリフォト・ファクターで人類を救えると？","ENG":"Did Na Yubin tell you? That the Qliphoth Factor will save mankind?","TWN":"是羅瑜斌那樣說的嗎？逆卡巴拉因子可以拯救人類？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"미안하지만 넌 그 녀석에게 그냥 속은 거야.","JPN":"悪いが、お前はあいつにまんまと騙されたんだ。","ENG":"I'm sorry, but that kid was just messing with you.","TWN":"很可惜，妳被他騙了。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};